 50	  createNoobaaExternalPostgresResources,
 51	  createStorageCluster,
 52	  labelNodes,
 53	  taintNodes,
 54	  createOCSNamespace,
 55	  createStorageAutoScaler,
 56	} from './payloads';
 57	import { WizardCommonProps, WizardState } from './reducer';
 58	
 59	// Not to be exposed to other files to make our code name agnostic
 60	const OCS_INTERNAL_CR_NAME = 'ocs-storagecluster';
 61	const NOOBAA_DB_BACKUP_VOLUMESNAPSHOTCLASS =
 62	  getRBDVolumeSnapshotClassName(OCS_INTERNAL_CR_NAME);
 63	const validateBackingStorageStep = (
 64	  backingStorage: WizardState['backingStorage'],
 65	  sc: WizardState['storageClass']
 66	) => {
 67	  const { type, externalStorage, deployment } = backingStorage;
 68	
 69	  switch (type) {
 70	    case BackingStorageType.EXISTING:
 71	      return !!sc.name && !!deployment;
 72	    case BackingStorageType.EXTERNAL:
 73	      return !!externalStorage;
 74	    case BackingStorageType.LOCAL_DEVICES:
 75	      return !!deployment;
 76	    default:
 77	      return false;
 78	  }
 79	};
 80	
 81	const validateAdvancedSettingsStep = (
 82	  advancedSettings: WizardState['advancedSettings'],
 83	  sc: WizardState['storageClass'],
 84	  deployment: DeploymentType,
 85	  type: BackingStorageType
 86	) => {
 87	  const {
 88	    enableNFS,
 89	    useExternalPostgres,
 90	    externalPostgres,
 91	    isDbBackup,
 92	    dbBackup,
 93	  } = advancedSettings;
 94	
 95	  const {
 96	    username,
 97	    password,
 98	    serverName,
 99	    port,
100	    databaseName,
101	    tls: { enableClientSideCerts, keys },
102	  } = externalPostgres;
103	
104	  const isMCG: boolean = deployment === DeploymentType.MCG;
105	
106	  const hasPGEnabledButNoFields =
107	    useExternalPostgres &&
108	    (!username || !password || !serverName || !port || !databaseName);
109	
110	  const hasClientCertsEnabledButNoKeys =
111	    enableClientSideCerts && (!keys.private || !keys.public);
112	
113	  // The Next button is disabled only when no VolumeSnapshotClass is selected for MCG Standalone when automatic backup option enabled.
114	  const hasDbBackupEnabledButNoFields =
115	    isDbBackup && !dbBackup.volumeSnapshot?.volumeSnapshotClass && isMCG;
116	
117	  switch (type) {
118	    case BackingStorageType.EXISTING:
119	      return (
120	        !!sc.name &&
121	        !!deployment &&
122	        !hasPGEnabledButNoFields &&
123	        !hasClientCertsEnabledButNoKeys &&
124	        !hasDbBackupEnabledButNoFields
125	      );
126	    case BackingStorageType.EXTERNAL:
127	      return (
128	        !enableNFS &&
129	        !hasPGEnabledButNoFields &&
130	        !hasClientCertsEnabledButNoKeys &&
131	        !hasDbBackupEnabledButNoFields
132	      );
133	    case BackingStorageType.LOCAL_DEVICES:
134	      return (
135	        !!deployment &&
136	        !hasPGEnabledButNoFields &&
137	        !hasClientCertsEnabledButNoKeys &&
138	        !hasDbBackupEnabledButNoFields
139	      );
140	    default:
141	      return false;
142	  }
143	};
144	const canJumpToNextStep = (
145	  name: string,
146	  state: WizardState,
147	  t: TFunction,
148	  supportedExternalStorage: ExternalStorage[]
149	) => {
150	  const {
151	    storageClass,
152	    backingStorage,
153	    createStorageClass,
154	    capacityAndNodes,
155	    createLocalVolumeSet,
156	    securityAndNetwork,
157	    connectionDetails,
158	    nodes,
159	    advancedSettings,
160	  } = state;
161	  const { type, externalStorage } = backingStorage;
162	  const isExternal: boolean = type === BackingStorageType.EXTERNAL;
163	  const isRHCS: boolean = externalStorage === StorageClusterModel.kind;
164	  const {
165	    capacity,
166	    enableArbiter,
167	    pvCount,
168	    resourceProfile,
169	    volumeValidationType,
170	  } = capacityAndNodes;
171	  const { chartNodes, volumeSetName, isValidDiskSize, isValidDeviceType } =
172	    createLocalVolumeSet;
173	  const { encryption, kms, networkType, publicNetwork, clusterNetwork } =
174	    securityAndNetwork;
175	  const { canGoToNextStep } =
176	    getExternalStorage(externalStorage, supportedExternalStorage) || {};
177	
178	  const hasConfiguredNetwork =
179	    networkType === NetworkType.MULTUS
180	      ? !!(publicNetwork || clusterNetwork)
181	      : true;
182	
183	  const isNoProvisioner = storageClass.provisioner === NO_PROVISIONER;
184	  const flexibleScaling = isFlexibleScaling(
185	    nodes,
186	    isNoProvisioner,
187	    enableArbiter
188	  );
189	  const deviceSetReplica: number = getDeviceSetReplica(
190	    enableArbiter,
191	    flexibleScaling,
192	    nodes
193	  );
194	  const deviceSetCount = getDeviceSetCount(pvCount, deviceSetReplica);
195	  const osdAmount = getOsdAmount(deviceSetCount, deviceSetReplica);
196	
197	  switch (name) {
198	    case StepsName(t)[Steps.BackingStorage]:
199	      return validateBackingStorageStep(backingStorage, storageClass);
200	    case StepsName(t)[Steps.AdvancedSettings]:
201	      return validateAdvancedSettingsStep(
202	        advancedSettings,
203	        storageClass,
204	        backingStorage.deployment,
205	        backingStorage.type
206	      );
207	    case StepsName(t)[Steps.CreateStorageClass]:
208	      return (
209	        !!storageClass.name &&
210	        canGoToNextStep &&
211	        canGoToNextStep(createStorageClass, storageClass.name)
212	      );
213	    case StepsName(t)[Steps.CreateLocalVolumeSet]:
214	      return (
215	        // "chartNodes.size === 0" signify no SSDs are attached, but no need to add that as it's already covered by "chartNodes.size >= MINIMUM_NODES" condition
216	        chartNodes.size >= MINIMUM_NODES &&
217	        volumeSetName.trim().length &&
218	        isValidDiskSize &&
219	        isValidDeviceType
220	      );
221	    case StepsName(t)[Steps.CapacityAndNodes]:
222	      return (
223	        nodes.length >= MINIMUM_NODES &&
224	        capacity &&
225	        ![VolumeTypeValidation.UNKNOWN, VolumeTypeValidation.ERROR].includes(
226	          volumeValidationType
227	        ) &&
228	        isResourceProfileAllowed(
229	          resourceProfile,
230	          getTotalCpu(nodes),
231	          getTotalMemoryInGiB(nodes),
232	          osdAmount
233	        ) &&
234	        isValidCapacityAutoScalingConfig(
235	          capacityAndNodes.capacityAutoScaling.enable,
236	          capacityAndNodes.capacityAutoScaling.capacityLimit
237	        )
238	      );
239	    case StepsName(t)[Steps.SecurityAndNetwork]:
240	      if (isExternal && isRHCS) {
241	        return canGoToNextStep(connectionDetails, storageClass.name);
242	      }
243	      return (
244	        encryption.hasHandled &&
245	        kms.providerState.hasHandled &&
246	        hasConfiguredNetwork
247	      );
248	    case StepsName(t)[Steps.Security]:
249	      return encryption.hasHandled && kms.providerState.hasHandled;
250	    case StepsName(t)[Steps.ReviewAndCreate]:
251	      return true;
252	    default:
253	      return false;
254	  }
255	};
256	
257	const handleReviewAndCreateNext = async (
258	  state: WizardState,
259	  handleError: (err: string, showError: boolean) => void,
260	  navigate,
261	  odfNamespace: string,
262	  existingNamespaces: K8sResourceCommon[]
263	) => {
264	  const { nodes, capacityAndNodes } = state;
265	  const { systemNamespace, deployment, type } = state.backingStorage;
266	  const { useExternalPostgres, externalPostgres } = state.advancedSettings;
267	  const { encryption, kms } = state.securityAndNetwork;
268	  const isMCG: boolean = deployment === DeploymentType.MCG;
269	  const nsAlreadyExists = !!existingNamespaces.find(
270	    (ns) => getName(ns) === systemNamespace
271	  );
272	
273	  const createNooBaaResources = async () => {
274	    if (useExternalPostgres) {
275	      let keyTexts = { private: '', public: '' };
276	      if (externalPostgres.tls.enableClientSideCerts) {
277	        const keys = externalPostgres.tls.keys;
278	        const privateKey = await keys.private.text();
279	        const publicKey = await keys.public.text();
280	        keyTexts = { private: privateKey, public: publicKey };
281	      }
282	      await Promise.all(
283	        createNoobaaExternalPostgresResources(
284	          systemNamespace,
285	          externalPostgres,
286	          keyTexts
287	        )
288	      );
289	    }
290	  };
291	
292	  const createAdditionalFeatureResources = async () => {
293	    if (capacityAndNodes.enableTaint && !isMCG) await taintNodes(nodes);
294	
295	    /**
296	     * CSI KMS ConfigMap and Secrets always needs to be created in ODF install namespace (that is, where Rook is deployed),
297	     * whereas OCS KMS ConfigMap and Secrets needs to be created in the namespace where Ceph is being deployed (StorageSystem namespace).
298	     * ToDo: External mode do not support KMS and only single Internal mode is allowed, so it should work for now,
299	     * but in future, if need arises, first check whether CSI ConfigMap already exists or not before creating KMS related resources for multiple clusters.
300	     * Also, change name of "ceph-csi-kms-token" token Secret (if need to create multiple in Rook namespace).
301	     */
302	    if (encryption.advanced)
303	      // as currently only one internal cluster is allowed, "systemNamespace" (where intenal cluster is being created) and "odfNamespace" (where ODF is installed) will be same
304	      await Promise.all(
305	        createClusterKmsResources(
306	          kms.providerState,
307	          systemNamespace,
308	          odfNamespace,
309	          kms.provider,
310	          isMCG
311	        )
312	      );
313	
314	    await createNooBaaResources();
315	  };
316	
317	  try {
318	    systemNamespace === odfNamespace || nsAlreadyExists
319	      ? await labelOCSNamespace(systemNamespace)
320	      : await createOCSNamespace(systemNamespace);
321	
322	    let storageCluster: StorageClusterKind;
323	    if (isMCG) {
324	      await createAdditionalFeatureResources();
325	      storageCluster = await createStorageCluster(
326	        state,
327	        systemNamespace,
328	        OCS_INTERNAL_CR_NAME
329	      );
330	    } else if (
331	      type === BackingStorageType.EXISTING ||
332	      type === BackingStorageType.LOCAL_DEVICES
333	    ) {
334	      await labelNodes(nodes, systemNamespace);
335	      await createAdditionalFeatureResources();
336	      storageCluster = await createStorageCluster(
337	        state,
338	        systemNamespace,
339	        OCS_INTERNAL_CR_NAME
340	      );
341	    }
342	    if (storageCluster) {
343	      try {
344	        // Delete preexisting ui-created autoscaler to avoid a misconfiguration.
345	        await k8sDelete({
346	          model: StorageAutoScalerModel,
347	          resource: {
348	            metadata: {
349	              name: getStorageAutoScalerName(storageCluster),
350	              namespace: getNamespace(storageCluster),
351	            },
352	          },
353	        });
354	      } catch (error) {
355	        // It's OK if it didn't exist.
356	        if (!isNotFoundError(error)) {
357	          // eslint-disable-next-line no-console
358	          console.error(
359	            `Error while deleting preexisting capacity autoscaling: ${error.message}`
360	          );
361	        }
362	      }
363	      if (state.capacityAndNodes.capacityAutoScaling.enable) {
364	        // Don't stop the workflow on autoscaler creation error.
365	        try {
366	          await createStorageAutoScaler(
367	            state.capacityAndNodes.capacityAutoScaling.capacityLimit,
368	            storageCluster
369	          );
370	        } catch (error) {
371	          // TODO: raise a notification once the notification system is implemented.
372	          // eslint-disable-next-line no-console
373	          console.error(
374	            `Error while enabling capacity autoscaling: ${error.message}`
375	          );
376	        }
377	      }
378	    }
379	    navigate('/odf/storage-cluster');
380	  } catch (err) {
381	    handleError(err.message, true);
382	  }
383	};
384	
385	export const CreateStorageSystemFooter: React.FC<
386	  CreateStorageSystemFooterProps
387	> = ({
388	  dispatch,
389	  state,
390	  disableNext,
391	  supportedExternalStorage,
392	  existingNamespaces,
393	}) => {
394	  const { t } = useCustomTranslation();
395	  const navigate = useNavigate();
396	  const { activeStep, goToNextStep, goToPrevStep } = useWizardContext();
397	
398	  const { odfNamespace, isNsSafe } = useODFNamespaceSelector();
399	
400	  const [requestInProgress, setRequestInProgress] = React.useState(false);
401	  const [requestError, setRequestError] = React.useState('');
402	  const [showErrorAlert, setShowErrorAlert] = React.useState(false);
403	
404	  const stepName = activeStep.name as string;
405	  const { deployment } = state.backingStorage;
406	  const { isDbBackup } = state.advancedSettings;
407	  const isMCG: boolean = deployment === DeploymentType.MCG;
408	
409	  const jumpToNextStep = canJumpToNextStep(
410	    stepName,
411	    state,
412	    t,
413	    supportedExternalStorage
414	  );
415	
416	  const moveToNextStep = () => {
417	    goToNextStep();
418	  };
419	
420	  const handleError = (errorMessage: string, showError: boolean) => {
421	    setRequestError(errorMessage);
422	    setShowErrorAlert(showError);
423	  };
424	
425	  const handleNext = async () => {
426	    switch (stepName) {
427	      case StepsName(t)[Steps.CreateLocalVolumeSet]:
428	        dispatch({
429	          type: 'wizard/setCreateLocalVolumeSet',
430	          payload: { field: 'showConfirmModal', value: true },
431	        });
432	        break;
433	      case StepsName(t)[Steps.AdvancedSettings]:
434	        // Auto-select the RBD VolumeSnapshotClass for internal mode when automatic backup is enabled.
435	        if (isDbBackup && !isMCG) {
436	          dispatch({
437	            type: 'advancedSettings/dbBackup/volumeSnapshot/volumeSnapshotClass',
438	            payload: NOOBAA_DB_BACKUP_VOLUMESNAPSHOTCLASS,
439	          });
440	        }
441	        moveToNextStep();
442	        break;
443	      case StepsName(t)[Steps.ReviewAndCreate]:
444	        setRequestInProgress(true);
445	        await handleReviewAndCreateNext(
446	          state,
447	          handleError,
448	          navigate,
449	          odfNamespace,
450	          existingNamespaces
451	        );
452	        setRequestInProgress(false);
453	        break;
454	      default:
455	        moveToNextStep();
456	    }
457	  };
458	
459	  return (
460	    <>
461	      {showErrorAlert && (
462	        <Alert
463	          className="odf-create-storage-system-footer__alert"
464	          variant="danger"
465	          isInline
466	          actionClose={
467	            <AlertActionCloseButton onClose={() => handleError('', false)} />
468	          }
469	          title={t('An error has occurred')}
470	        >
471	          {requestError}
472	        </Alert>
473	      )}
474	      <WizardFooterWrapper>
475	        <Button
476	          isLoading={requestInProgress || null}
477	          isDisabled={
478	            disableNext || requestInProgress || !jumpToNextStep || !isNsSafe
479	          }
480	          variant="primary"
481	          onClick={handleNext}
482	        >
483	          {stepName === StepsName(t)[Steps.ReviewAndCreate]
484	            ? t('Create storage system')
485	            : t('Next')}
486	        </Button>
487	        {/* Disabling the back button for the first step (Backing storage) in wizard */}
488	        <Button
489	          variant="secondary"
490	          onClick={goToPrevStep}
491	          isDisabled={
492	            stepName === StepsName(t)[Steps.BackingStorage] ||
493	            requestInProgress ||
494	            !isNsSafe
495	          }
496	        >
497	          {t('Back')}
498	        </Button>
499	        <Button
500	          variant="link"
501	          onClick={() => navigate(-1)}
502	          isDisabled={requestInProgress}
503	        >
504	          {t('Cancel')}
505	        </Button>
506	      </WizardFooterWrapper>
507	    </>
508	  );
509	};
510	
511	type CreateStorageSystemFooterProps = WizardCommonProps & {
512	  disableNext: boolean;
513	  hasOCS: boolean;
514	  supportedExternalStorage: ExternalStorage[];
515	  existingNamespaces: K8sResourceCommon[];
516	};

